class Solution(object):
    def countQuadruplets(self, nums):
        n = len(nums)
        count = 0
        for a in range(n):
            for b in range(a + 1, n):
                for c in range(b + 1, n):
                    for d2 in range(c + 1, n):
                        if nums[a] + nums[b] + nums[c] == nums[d2]:
                            count += 1
        return count
